spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    // Stages
    var stage = 1;
    if (progress >= 0.25 && progress < 0.50) stage = 2;
    else if (progress >= 0.50 && progress < 0.75) stage = 3;
    else if (progress >= 0.75) stage = 4;

    var midY = H / 2 - 20;
    var midX = W / 2;
    var step = (W - 80) / 7; // spacing for 0 to 6
    var startX = 40;

    // Draw axis line
    ctx.strokeStyle = '#4B5563';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(20, midY);
    ctx.lineTo(W - 20, midY);
    ctx.stroke();

    // Draw tick marks and labels for 0 to 6
    ctx.textAlign = 'center';
    ctx.textBaseline = 'top';
    ctx.font = '12px monospace';
    for (var i = 0; i <= 6; i++) {
      var tx = startX + i * step;
      ctx.strokeStyle = '#4B5563';
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      ctx.moveTo(tx, midY - 4);
      ctx.lineTo(tx, midY + 4);
      ctx.stroke();

      ctx.fillStyle = (i === 3 || i === 5) ? '#F59E0B' : '#9CA3AF';
      ctx.fillText(i.toString(), tx, midY + 8);
    }

    // Calculate animated dot X
    var dotX = startX + 3 * step;
    if (stage === 3) {
      var walkProgress = (progress - 0.50) / 0.25;
      dotX = startX + (3 + 2 * walkProgress) * step;
    } else if (stage === 4) {
      dotX = startX + 5 * step;
    }

    // Draw arrow orientation indicating 'facing direction'
    var arrowDir = -1; // subtraction face left
    if (stage >= 3) arrowDir = 1; // walking backward makes motion go right

    // Draw current position dot
    ctx.fillStyle = '#EF4444';
    ctx.beginPath();
    ctx.arc(dotX, midY, 6, 0, Math.PI * 2);
    ctx.fill();

    // Draw direction indicator arrow above dot
    if (stage === 2) {
      ctx.strokeStyle = '#38BDF8';
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(dotX, midY - 15);
      ctx.lineTo(dotX - 15, midY - 15);
      ctx.stroke();
      // Arrow head facing left
      ctx.fillStyle = '#38BDF8';
      ctx.beginPath();
      ctx.moveTo(dotX - 18, midY - 15);
      ctx.lineTo(dotX - 12, midY - 19);
      ctx.lineTo(dotX - 12, midY - 11);
      ctx.closePath();
      ctx.fill();
    } else if (stage === 3) {
      // Walking backwards indicator
      ctx.strokeStyle = '#F59E0B';
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(dotX, midY - 15);
      ctx.lineTo(dotX - 10, midY - 15);
      ctx.stroke();

      ctx.font = '10px sans-serif';
      ctx.fillStyle = '#F59E0B';
      ctx.fillText('Walking backward', dotX, midY - 30);
    }

    // Bottom text explanations
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = 'bold 15px -apple-system, sans-serif';
    ctx.fillStyle = '#F3F4F6';

    if (stage === 1) {
      ctx.fillText('Start at 3', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Position is at positive 3 on the number line.', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#38BDF8';
      ctx.fillText('Subtract (-) → Face Left', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Subtraction tells the character to face the negative direction.', W / 2, H - 22);
    } else if (stage === 3) {
      ctx.fillStyle = '#FBBF24';
      ctx.fillText('Subtracting a Negative (-2) → Move Backward', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Walking backward while facing left shifts the dot to the right.', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#10B981';
      ctx.fillText('Result: 3 - (-2) = 3 + 2 = 5', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Subtracting a negative has the exact same effect as adding a positive!', W / 2, H - 22);
    }
  }
};
